import{A as e,f as t,h as n,t as r}from"./chunks/plugin-vue_export-helper.I53torQa.js";var i=JSON.parse(`{"title":"多智能体强化学习代码库汇总","description":"汇总基于 PyTorch 的多智能体强化学习开源代码库","frontmatter":{"title":"多智能体强化学习代码库汇总","description":"汇总基于 PyTorch 的多智能体强化学习开源代码库"},"headers":[],"relativePath":"rl/tools/marl-code-libraries.md","filePath":"rl/tools/marl-code-libraries.md","lastUpdated":1782721961000}`),a={name:`rl/tools/marl-code-libraries.md`};function o(r,i,a,o,s,c){return e(),t(`div`,null,[...i[0]||=[n(`<h1 id="多智能体强化学习代码库汇总" tabindex="-1">多智能体强化学习代码库汇总 <a class="header-anchor" href="#多智能体强化学习代码库汇总" aria-label="Permalink to “多智能体强化学习代码库汇总”">​</a></h1><h2 id="algorithms" tabindex="-1">Algorithms <a class="header-anchor" href="#algorithms" aria-label="Permalink to “Algorithms”">​</a></h2><p>We provide three types of MARL algorithms as our baselines including:</p><h3 id="independent-learning" tabindex="-1">Independent Learning <a class="header-anchor" href="#independent-learning" aria-label="Permalink to “Independent Learning”">​</a></h3><ul><li>IQL</li><li>DDPG</li><li>PG</li><li>A2C</li><li>TRPO</li><li>PPO</li></ul><h3 id="centralized-critic" tabindex="-1">Centralized Critic <a class="header-anchor" href="#centralized-critic" aria-label="Permalink to “Centralized Critic”">​</a></h3><ul><li>COMA</li><li>MADDPG</li><li>MAAC</li><li>MAPPO</li><li>MATRPO</li><li>HATRPO</li><li>HAPPO</li></ul><h3 id="value-decomposition" tabindex="-1">Value Decomposition <a class="header-anchor" href="#value-decomposition" aria-label="Permalink to “Value Decomposition”">​</a></h3><ul><li>VDN</li><li>QMIX</li><li>FACMAC</li><li>VDAC</li><li>VDPPO</li></ul><p>Here is a chart describing the characteristics of each algorithm:</p><div class="vp-table-wrapper"><table tabindex="0"><thead><tr><th>Algorithm</th><th>Support Task Mode</th><th>Need Central Information</th><th>Discrete Action</th><th>Continuous Action</th><th>Learning Categorize</th><th>Type</th></tr></thead><tbody><tr><td>IQL*</td><td>cooperative collaborative competitive mixed</td><td></td><td>✔️</td><td></td><td>Independent Learning</td><td>Off Policy</td></tr><tr><td><a href="https://papers.nips.cc/paper/1713-policy-gradient-methods-for-reinforcement-learning-with-function-approximation.pdf" target="_blank" rel="noreferrer">PG</a></td><td>cooperative collaborative competitive mixed</td><td></td><td>✔️</td><td>✔️</td><td>Independent Learning</td><td>On Policy</td></tr><tr><td><a href="https://arxiv.org/abs/1602.01783" target="_blank" rel="noreferrer">A2C</a></td><td>cooperative collaborative competitive mixed</td><td></td><td>✔️</td><td>✔️</td><td>Independent Learning</td><td>On Policy</td></tr><tr><td><a href="https://arxiv.org/abs/1509.02971" target="_blank" rel="noreferrer">DDPG</a></td><td>cooperative collaborative competitive mixed</td><td></td><td></td><td>✔️</td><td>Independent Learning</td><td>Off Policy</td></tr><tr><td><a href="http://proceedings.mlr.press/v37/schulman15.pdf" target="_blank" rel="noreferrer">TRPO</a></td><td>cooperative collaborative competitive mixed</td><td></td><td>✔️</td><td>✔️</td><td>Independent Learning</td><td>On Policy</td></tr><tr><td><a href="https://arxiv.org/abs/1707.06347" target="_blank" rel="noreferrer">PPO</a></td><td>cooperative collaborative competitive mixed</td><td></td><td>✔️</td><td>✔️</td><td>Independent Learning</td><td>On Policy</td></tr><tr><td><a href="https://ojs.aaai.org/index.php/AAAI/article/download/11794/11653" target="_blank" rel="noreferrer">COMA</a></td><td>cooperative collaborative competitive mixed</td><td>✔️</td><td>✔️</td><td></td><td>Centralized Critic</td><td>On Policy</td></tr><tr><td><a href="https://arxiv.org/abs/1706.02275" target="_blank" rel="noreferrer">MADDPG</a></td><td>cooperative collaborative competitive mixed</td><td>✔️</td><td></td><td>✔️</td><td>Centralized Critic</td><td>Off Policy</td></tr><tr><td>MAA2C*</td><td>cooperative collaborative competitive mixed</td><td>✔️</td><td>✔️</td><td>✔️</td><td>Centralized Critic</td><td>On Policy</td></tr><tr><td>MATRPO*</td><td>cooperative collaborative competitive mixed</td><td>✔️</td><td>✔️</td><td>✔️</td><td>Centralized Critic</td><td>On Policy</td></tr><tr><td><a href="https://arxiv.org/abs/2103.01955" target="_blank" rel="noreferrer">MAPPO</a></td><td>cooperative collaborative competitive mixed</td><td>✔️</td><td>✔️</td><td>✔️</td><td>Centralized Critic</td><td>On Policy</td></tr><tr><td><a href="https://arxiv.org/abs/2109.11251" target="_blank" rel="noreferrer">HATRPO</a></td><td>Cooperative</td><td>✔️</td><td>✔️</td><td>✔️</td><td>Centralized Critic</td><td>On Policy</td></tr><tr><td><a href="https://arxiv.org/abs/2109.11251" target="_blank" rel="noreferrer">HAPPO</a></td><td>Cooperative</td><td>✔️</td><td>✔️</td><td>✔️</td><td>Centralized Critic</td><td>On Policy</td></tr><tr><td><a href="https://arxiv.org/abs/1706.05296" target="_blank" rel="noreferrer">VDN</a></td><td>Cooperative</td><td></td><td>✔️</td><td></td><td>Value Decomposition</td><td>Off Policy</td></tr><tr><td><a href="https://arxiv.org/abs/1803.11485" target="_blank" rel="noreferrer">QMIX</a></td><td>Cooperative</td><td>✔️</td><td>✔️</td><td></td><td>Value Decomposition</td><td>Off Policy</td></tr><tr><td><a href="https://arxiv.org/abs/2003.06709" target="_blank" rel="noreferrer">FACMAC</a></td><td>Cooperative</td><td>✔️</td><td></td><td>✔️</td><td>Value Decomposition</td><td>Off Policy</td></tr><tr><td><a href="https://arxiv.org/abs/2007.12306" target="_blank" rel="noreferrer">VDAC</a></td><td>Cooperative</td><td>✔️</td><td>✔️</td><td>✔️</td><td>Value Decomposition</td><td>On Policy</td></tr><tr><td>VDPPO*</td><td>Cooperative</td><td>✔️</td><td>✔️</td><td>✔️</td><td>Value Decomposition</td><td>On Policy</td></tr></tbody></table></div><p><em>IQL</em> is the multi-agent version of Q learning. <em>MAA2C</em> and <em>MATRPO</em> are the centralized version of A2C and TRPO. <em>VDPPO</em> is the value decomposition version of PPO.</p><h2 id="awesome-repos" tabindex="-1">Awesome Repos <a class="header-anchor" href="#awesome-repos" aria-label="Permalink to “Awesome Repos”">​</a></h2><p>Here we provide a table for the comparison of MARLlib and existing work.</p><div class="vp-table-wrapper"><table tabindex="0"><thead><tr><th style="text-align:center;">Library</th><th style="text-align:center;">Github Stars</th><th style="text-align:center;">Task Mode</th><th style="text-align:center;">Supported Env</th><th style="text-align:center;">Algorithm</th><th style="text-align:center;">Parameter Sharing</th><th style="text-align:center;">Asynchronous Interact</th><th style="text-align:center;">Framework</th></tr></thead><tbody><tr><td style="text-align:center;"><a href="https://github.com/oxwhirl/pymarl" target="_blank" rel="noreferrer">PyMARL</a></td><td style="text-align:center;"><a href="https://github.com/oxwhirl/pymarl/stargazers" target="_blank" rel="noreferrer"><img src="https://img.shields.io/github/stars/oxwhirl/pymarl" alt="GitHub stars"></a></td><td style="text-align:center;">cooperative</td><td style="text-align:center;">1</td><td style="text-align:center;">Independent Learning(1) + Centralized Critic(1) + Value Decomposition(3)</td><td style="text-align:center;">full-sharing</td><td style="text-align:center;"></td><td style="text-align:center;">*</td></tr><tr><td style="text-align:center;"><a href="https://github.com/hijkzzz/pymarl2" target="_blank" rel="noreferrer">PyMARL2</a></td><td style="text-align:center;"><a href="https://github.com/hijkzzz/pymarl2/stargazers" target="_blank" rel="noreferrer"><img src="https://img.shields.io/github/stars/hijkzzz/pymarl2" alt="GitHub stars"></a></td><td style="text-align:center;">cooperative</td><td style="text-align:center;">1</td><td style="text-align:center;">Independent Learning(1) + Centralized Critic(1) + Value Decomposition(9)</td><td style="text-align:center;">full-sharing</td><td style="text-align:center;"></td><td style="text-align:center;">PyMARL</td></tr><tr><td style="text-align:center;"><a href="https://github.com/starry-sky6688/MARL-Algorithms" target="_blank" rel="noreferrer">MARL-Algorithms</a></td><td style="text-align:center;"><a href="https://github.com/starry-sky6688/MARL-Algorithms/stargazers" target="_blank" rel="noreferrer"><img src="https://img.shields.io/github/stars/starry-sky6688/MARL-Algorithms" alt="GitHub stars"></a></td><td style="text-align:center;">cooperative</td><td style="text-align:center;">1</td><td style="text-align:center;">CTDE(6) + Communication(1) + Graph(1) + Multi-task(1)</td><td style="text-align:center;">full-sharing</td><td style="text-align:center;"></td><td style="text-align:center;">*</td></tr><tr><td style="text-align:center;"><a href="https://github.com/uoe-agents/epymarl" target="_blank" rel="noreferrer">EPyMARL</a></td><td style="text-align:center;"><a href="https://github.com/uoe-agents/epymarl/stargazers" target="_blank" rel="noreferrer"><img src="https://img.shields.io/github/stars/uoe-agents/epymarl" alt="GitHub stars"></a></td><td style="text-align:center;">cooperative</td><td style="text-align:center;">4</td><td style="text-align:center;">Independent Learning(3) + Value Decomposition(4) + Centralized Critic(2)</td><td style="text-align:center;">full-sharing + non-sharing</td><td style="text-align:center;"></td><td style="text-align:center;">PyMARL</td></tr><tr><td style="text-align:center;"><a href="https://github.com/sjtu-marl/malib" target="_blank" rel="noreferrer">MAlib</a></td><td style="text-align:center;"><a href="https://github.com/sjtu-marl/malib/stargazers" target="_blank" rel="noreferrer"><img src="https://img.shields.io/github/stars/sjtu-marl/malib" alt="GitHub stars"></a></td><td style="text-align:center;">self-play</td><td style="text-align:center;">2 + <a href="https://www.pettingzoo.ml/" target="_blank" rel="noreferrer">PettingZoo</a> + <a href="https://github.com/deepmind/open_spiel" target="_blank" rel="noreferrer">OpenSpiel</a></td><td style="text-align:center;">Population-based</td><td style="text-align:center;">full-sharing + group-sharing + non-sharing</td><td style="text-align:center;">✔️</td><td style="text-align:center;">*</td></tr><tr><td style="text-align:center;"><a href="https://github.com/marlbenchmark/on-policy" target="_blank" rel="noreferrer">MAPPO Benchmark</a></td><td style="text-align:center;"><a href="https://github.com/marlbenchmark/on-policy/stargazers" target="_blank" rel="noreferrer"><img src="https://img.shields.io/github/stars/marlbenchmark/on-policy" alt="GitHub stars"></a></td><td style="text-align:center;">cooperative</td><td style="text-align:center;">4</td><td style="text-align:center;">MAPPO(1)</td><td style="text-align:center;">full-sharing + non-sharing</td><td style="text-align:center;">✔️</td><td style="text-align:center;">pytorch-a2c-ppo-acktr-gail</td></tr><tr><td style="text-align:center;"><a href="https://github.com/Replicable-MARL/MARLlib" target="_blank" rel="noreferrer">MARLlib</a></td><td style="text-align:center;"></td><td style="text-align:center;">cooperative collaborative competitive mixed</td><td style="text-align:center;">10 + <a href="https://www.pettingzoo.ml/" target="_blank" rel="noreferrer">PettingZoo</a></td><td style="text-align:center;">Independent Learning(6) + Centralized Critic(7) + Value Decomposition(5)</td><td style="text-align:center;">full-sharing + group-sharing + non-sharing</td><td style="text-align:center;">✔️</td><td style="text-align:center;">Ray/Rllib</td></tr></tbody></table></div><h2 id="some-comments" tabindex="-1">Some comments <a class="header-anchor" href="#some-comments" aria-label="Permalink to “Some comments”">​</a></h2><ol><li>starry-sky6688</li></ol><p>这套代码简单易上手，适合初学者入门。包含 IQL、QMIX、VDN、COMA、QTRAN、MAVEN、CommNet、DyMA-CL、G2ANet 和 MADDPG。</p><ul><li><p><a href="https://github.com/starry-sky6688/MARL-Algorithms" target="_blank" rel="noreferrer">https://github.com/starry-sky6688/MARL-Algorithms</a></p></li><li><p><a href="https://github.com/starry-sky6688/MADDPG" target="_blank" rel="noreferrer">https://github.com/starry-sky6688/MADDPG</a></p></li></ul><ol start="2"><li>pymarl</li></ol><p>牛津大学 whiteson 组的代码库，非常模块化的代码，是那种很好用但也很难上手的类型。包括 QMIX、COMA、VDN、IQL、QTRAN。</p><ul><li><a href="https://github.com/oxwhirl/pymarl" target="_blank" rel="noreferrer">https://github.com/oxwhirl/pymarl</a></li></ul><ol start="3"><li>pymarl2 （351 星）</li></ol><p>pymarl 的改进版本, 增加了一些 code-level tricks。</p><ul><li><p><a href="https://arxiv.org/abs/2102.03479" target="_blank" rel="noreferrer">https://arxiv.org/abs/2102.03479</a></p></li><li><p><a href="https://github.com/hijkzzz/pymarl2" target="_blank" rel="noreferrer">https://github.com/hijkzzz/pymarl2</a></p></li></ul><ol start="4"><li>epymarl （139 星）</li></ol><p>epymarl 的扩展版本，在 pymarl 的基础上增加了 IA2C、IPPO、MADDPG、MAA2C、MAPPO。</p><ul><li><a href="https://github.com/uoe-agents/epymarl" target="_blank" rel="noreferrer">https://github.com/uoe-agents/epymarl</a></li></ul><ol start="5"><li>shariqiqbal2810 （307 星）</li></ol><p>MAAC 作者写的代码，挺简洁的。包括 MADDPG、MAAC。</p><ul><li><p><a href="https://github.com/shariqiqbal2810/maddpg-pytorch" target="_blank" rel="noreferrer">https://github.com/shariqiqbal2810/maddpg-pytorch</a></p></li><li><p><a href="https://github.com/shariqiqbal2810/MAAC" target="_blank" rel="noreferrer">https://github.com/shariqiqbal2810/MAAC</a></p></li></ul><ol start="6"><li>marlbenchmark （509 星/102 星）</li></ol><p>清华大学的代码库，包含 MAPPO、QMIX、VDN、MADDPG 和 MATD3，其中 VDN 和 MATD3 没有经过完整测试。</p><ul><li><p><a href="https://github.com/marlbenchmark/on-policy" target="_blank" rel="noreferrer">https://github.com/marlbenchmark/on-policy</a></p></li><li><p><a href="https://github.com/marlbenchmark/off-policy" target="_blank" rel="noreferrer">https://github.com/marlbenchmark/off-policy</a></p></li></ul><ol start="7"><li>marllib （70 星）</li></ol><p>一个涵盖了大多主流 MARL 算法的代码库，基于 ray 的 rllib，属于那种模块化做得特别好，但上手需要花些时间的代码，包含 independence learning (IQL, A2C, DDPG, TRPO, PPO), centralized critic learning (COMA, MADDPG, MAPPO, HATRPO), and value decomposition (QMIX, VDN, FACMAC, VDA2C)。</p><ul><li><a href="https://github.com/Replicable-MARL/MARLlib" target="_blank" rel="noreferrer">https://github.com/Replicable-MARL/MARLlib</a></li></ul><h2 id="environments" tabindex="-1">Environments <a class="header-anchor" href="#environments" aria-label="Permalink to “Environments”">​</a></h2><p>Most of the popular environments in MARL research are supported by MARLlib:</p><div class="vp-table-wrapper"><table tabindex="0"><thead><tr><th>Env Name</th><th>Learning Mode</th><th>Observability</th><th>Action Space</th><th>Observations</th></tr></thead><tbody><tr><td><a href="https://github.com/semitable/lb-foraging" target="_blank" rel="noreferrer">LBF</a></td><td>cooperative + collaborative</td><td>Both</td><td>Discrete</td><td>Discrete</td></tr><tr><td><a href="https://github.com/semitable/robotic-warehouse" target="_blank" rel="noreferrer">RWARE</a></td><td>cooperative</td><td>Partial</td><td>Discrete</td><td>Discrete</td></tr><tr><td><a href="https://github.com/openai/multiagent-particle-envs" target="_blank" rel="noreferrer">MPE</a></td><td>cooperative + collaborative + mixed</td><td>Both</td><td>Both</td><td>Continuous</td></tr><tr><td><a href="https://github.com/oxwhirl/smac" target="_blank" rel="noreferrer">SMAC</a></td><td>cooperative</td><td>Partial</td><td>Discrete</td><td>Continuous</td></tr><tr><td><a href="https://github.com/decisionforce/metadrive" target="_blank" rel="noreferrer">MetaDrive</a></td><td>collaborative</td><td>Partial</td><td>Continuous</td><td>Continuous</td></tr><tr><td><a href="https://www.pettingzoo.ml/magent" target="_blank" rel="noreferrer">MAgent</a></td><td>collaborative + mixed</td><td>Partial</td><td>Discrete</td><td>Discrete</td></tr><tr><td><a href="https://github.com/MultiAgentLearning/playground" target="_blank" rel="noreferrer">Pommerman</a></td><td>collaborative + competitive + mixed</td><td>Both</td><td>Discrete</td><td>Discrete</td></tr><tr><td><a href="https://github.com/schroederdewitt/multiagent_mujoco" target="_blank" rel="noreferrer">MAMuJoCo</a></td><td>cooperative</td><td>Partial</td><td>Continuous</td><td>Continuous</td></tr><tr><td><a href="https://github.com/google-research/football" target="_blank" rel="noreferrer">GRF</a></td><td>collaborative + mixed</td><td>Full</td><td>Discrete</td><td>Continuous</td></tr><tr><td><a href="https://github.com/deepmind/hanabi-learning-environment" target="_blank" rel="noreferrer">Hanabi</a></td><td>cooperative</td><td>Partial</td><td>Discrete</td><td>Discrete</td></tr></tbody></table></div><p>Each environment has a readme file, standing as the instruction for this task, talking about env settings, installation, and some important notes.</p>`,41)]])}var s=r(a,[[`render`,o]]);export{i as __pageData,s as default};